diff:
diff --git a/src/catch2/internal/catch_textflow.cpp b/src/catch2/internal/catch_textflow.cpp
index 1c21d20..8b5c1b8 100644
--- a/src/catch2/internal/catch_textflow.cpp
+++ b/src/catch2/internal/catch_textflow.cpp
@@ -50,7 +50,10 @@ namespace Catch {
                     it = cursor + 1;
                 }
                 if ( it != m_string.end() ) {
-                    ++m_size;
+                    // Only count lead bytes (not UTF-8 continuation bytes 0x80-0xBF)
+                    if ( ( static_cast<unsigned char>( *it ) & 0xC0u ) != 0x80u ) {
+                        ++m_size;
+                    }
                     ++it;
                 }
             }
@@ -114,6 +117,11 @@ namespace Catch {
         void AnsiSkippingString::const_iterator::advance() {
             assert( m_it != m_string->end() );
             m_it++;
+            // skip UTF-8 continuation bytes so we move by one codepoint
+            while ( m_it != m_string->end() &&
+                    ( static_cast<unsigned char>( *m_it ) & 0xC0u ) == 0x80u ) {
+                ++m_it;
+            }
             tryParseAnsiEscapes();
         }
